FILE_PATH = "/Users/best/Library/CloudStorage/OneDrive-OrmesbyPrimary/GitProjects/axiiom/axiiom/industries/industries.txt"

with open(FILE_PATH, "r", encoding="utf-8") as f:
    lines = f.readlines()

# Determine which lines are incomplete (5 fields) starting from line index 6 (0-indexed)
# Line 6 (0-indexed) is erp-proizvodstvo which is complete.
updated_lines = []
count_updated = 0

for idx, line in enumerate(lines):
    line = line.rstrip("\n")
    if idx >= 6:  # lines 6+ in 0-indexed = lines 7+ in 1-indexed
        # Check if the line has only 5 fields
        fields = line.split("|")
        slug = fields[0] if fields else ""
        if slug in DATA and len(fields) == 5:
            entry = DATA[slug]
            modules_str = ":::".join(entry["modules"])
            cta_str = entry["cta"]
            flow_str = entry["flow"]
            new_line = f"{line}|{modules_str}|{cta_str}|{flow_str}"
            updated_lines.append(new_line)
            count_updated += 1
            print(f"✓ Updated: {slug}")
        else:
            if slug not in DATA and len(fields) == 5:
                print(f"✗ Skipped (unknown slug): {slug}")
            else:
                # Already has >5 fields or no match
                updated_lines.append(line)
                if len(fields) == 5:
                    print(f"— Skipped (not in DATA): {slug}")
    else:
        updated_lines.append(line)

with open(FILE_PATH, "w", encoding="utf-8") as f:
    f.write("\n".join(updated_lines) + "\n")

print(f"\nDone. Updated {count_updated} industries (lines 7–22).")
